import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useCart } from '../../context/CartContext';
import './Header.css';

const Header = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [mobileSearchOpen, setMobileSearchOpen] = useState(false);

  const { user, logout, isAuthenticated } = useAuth();
  const { getCartCount } = useCart();
  const navigate = useNavigate();

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      navigate(`/products?search=${searchQuery}`);
      setMobileSearchOpen(false);
    }
  };

  return (
    <header className="header">
      <div className="header-content">

        {/* Desktop Logo */}
        <Link to="/" className="logo logo-desktop">
  FixNFit
</Link>
{/* Mobile Logo */}
<Link to="/" className="logo logo-mobile">
  FixNFit
</Link>


        {/* Desktop Search */}
        <form className="search-bar desktop-search" onSubmit={handleSearch}>
          <input
            type="text"
            placeholder="Search for spare parts..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <button type="submit" className="search-btn">Search</button>
        </form>

        {/* Actions */}
        <div className="header-actions">

          {/* Mobile Search Icon */}
          <button
            className="mobile-search-btn"
            onClick={() => setMobileSearchOpen(true)}
          >
            🔍
          </button>

          {!isAuthenticated ? (
            <Link to="/login" className="btn btn-secondary">Login</Link>
          ) : (
            <button onClick={logout} className="btn btn-secondary">Logout</button>
          )}

          <Link to="/cart" className="cart-icon">
            🛒
            {getCartCount() > 0 && (
              <span className="cart-badge">{getCartCount()}</span>
            )}
          </Link>
        </div>
      </div>

      {/* Mobile Search Overlay */}
      {mobileSearchOpen && (
        <div className="mobile-search-overlay">
          <form className="mobile-search-bar" onSubmit={handleSearch}>
            <input
              autoFocus
              type="text"
              placeholder="Search for spare parts..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
            <button type="submit">Search</button>
            <button
              type="button"
              className="close-search"
              onClick={() => setMobileSearchOpen(false)}
            >
              ✕
            </button>
          </form>
        </div>
      )}
    </header>
  );
};

export default Header;
